#include <stdio.h>
#include <stdint.h>

static uint64_t countValid(uint32_t limit, uint32_t mask) {
    uint64_t dp_tight = 1, dp_loose = 0; // dp[tight]
    for (int i = 30; i >= 0; --i) {
        int bitL = (limit >> i) & 1;
        int bitM = (mask >> i) & 1;
        uint64_t ndp_tight = 0, ndp_loose = 0;
        // transitions from tight state
        if (dp_tight) {
            // allowed bits for V at this position
            for (int vb = 0; vb <= 1; ++vb) {
                if (bitM && vb) continue; // mask forces 0
                if (vb > bitL) continue; // would exceed limit
                if (vb == bitL) ndp_tight += dp_tight; // stay tight
                else ndp_loose += dp_tight; // become loose
            }
        }
        // transitions from loose state (already smaller)
        if (dp_loose) {
            for (int vb = 0; vb <= 1; ++vb) {
                if (bitM && vb) continue;
                ndp_loose += dp_loose; // any allowed vb keeps loose
            }
        }
        dp_tight = ndp_tight;
        dp_loose = ndp_loose;
    }
    return dp_tight + dp_loose;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint32_t N, X;
        scanf("%u %u", &N, &X);
        uint32_t base = N & X;
        if (base >= N) {
            printf("0\n");
            continue;
        }
        uint32_t limit = N - base;
        uint64_t ans = countValid(limit, X);
        printf("%llu\n", ans);
    }
    return 0;
}

