import java.io.*;
import java.util.*;

public class Main {
    private static long countValid(int limit, int mask) {
        long dpTight = 1, dpLoose = 0;
        for (int i = 30; i >= 0; --i) {
            int bitL = (limit >> i) & 1;
            int bitM = (mask >> i) & 1;
            long ndpTight = 0, ndpLoose = 0;
            if (dpTight != 0) {
                for (int vb = 0; vb <= 1; ++vb) {
                    if (bitM == 1 && vb == 1) continue;
                    if (vb > bitL) continue;
                    if (vb == bitL) ndpTight += dpTight;
                    else ndpLoose += dpTight;
                }
            }
            if (dpLoose != 0) {
                for (int vb = 0; vb <= 1; ++vb) {
                    if (bitM == 1 && vb == 1) continue;
                    ndpLoose += dpLoose;
                }
            }
            dpTight = ndpTight;
            dpLoose = ndpLoose;
        }
        return dpTight + dpLoose;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; ++t) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int X = Integer.parseInt(st.nextToken());
            int base = N & X;
            if (base >= N) {
                sb.append(0).append('\n');
                continue;
            }
            int limit = N - base;
            long ans = countValid(limit, X);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

