import sys

def count_valid(limit: int, mask: int) -> int:
    dp_tight, dp_loose = 1, 0
    for i in range(30, -1, -1):
        bitL = (limit >> i) & 1
        bitM = (mask >> i) & 1
        ndp_tight = ndp_loose = 0
        if dp_tight:
            for vb in (0, 1):
                if bitM and vb:
                    continue
                if vb > bitL:
                    continue
                if vb == bitL:
                    ndp_tight += dp_tight
                else:
                    ndp_loose += dp_tight
        if dp_loose:
            for vb in (0, 1):
                if bitM and vb:
                    continue
                ndp_loose += dp_loose
        dp_tight, dp_loose = ndp_tight, ndp_loose
    return dp_tight + dp_loose

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        X = int(next(it))
        base = N & X
        if base >= N:
            out_lines.append('0')
            continue
        limit = N - base
        ans = count_valid(limit, X)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

